// Convert the base64 image from the webhook payload into a binary file
// so Gmail can attach it to the email
// 1. Get the JSON data from the Webhook
const input = $input.first().json;

// 2. Extract data from the "body" object
const body = input.body || {}; 
const imageBase64 = body.image_base64;
const filename = body.image_filename || 'violation.jpg';

// 3. STOP logic: Ensure we have an agent report and it's not a 'safe' detection
if (!body.agent_report || body.violation_class === 'safe') {
  return []; 
}

if (!imageBase64) {
  throw new Error("Could not find image_base64 inside the webhook body!");
}

// 4. Return to n8n with the binary attachment
// We spread the 'body' object to ensure all fields are available directly
return [
  {
    json: {
      ...body
    },
    binary: {
      attachment: {
        data: imageBase64,
        mimeType: 'image/jpeg',
        fileName: filename,
        base64: true
      }
    }
  }
];
